export const ItemIconRenderer = ({ imagePath, className, size = 24 }: { imagePath: string, className?: string, size?: number }) => {
  const iconKey = imagePath.replace('/items/', '').replace('.svg', '');
  const IconComponent = JunkIconMap[iconKey];
  if (IconComponent) {
    return <IconComponent className={className} size={size} />;
  }
  return <img src={imagePath} alt="" className={className} style={{ width: size, height: size }} />;
};
